---@type BaseIconNew
local BaseIconNew = LXImport(".BaseIconNew")
------------------------------------------------------------------
---@class HalidomIconNew:BaseIconNew
local HalidomIconNew = LxClass("HalidomIconNew", BaseIconNew)

HalidomIconNew.DATA_TYPE_NORMAL = 0
HalidomIconNew.DATA_TYPE_SET = 1

-----------------------------------------------------------------

function HalidomIconNew:HalidomIconNew(wndClass)
    self:InitIconData()
end

function HalidomIconNew:InitIconData()
    self._showNum = false

    self._dataType = HalidomIconNew.DATA_TYPE_NORMAL

    self._refId = nil

    ---@type StructHalidomObjInfo
    self._halidomObj = nil

    self._displayStar = 0

    --- 显示满星级
    self._showMaxStarImg = false

    --- 默认用金色
    self._displayShowIconBg = "public_item_bg_7"
end

function HalidomIconNew:OnDestroy()

end
-----------------------------------------------------------------
function HalidomIconNew:ResetIcon()
    BaseIconNew.ResetIcon(self)
    self:InitIconData()
end

-----------------------------------------------------------------
function HalidomIconNew:ApplyIconUI()
    BaseIconNew.ApplyIconUI(self)

    self:SetIcon(self._displayShowIcon)
    CS.ShowObject(self._displayShowIconBg, true)
    self:SetIconBg(self._displayShowIconBg)

    self:UpdateShowMaxStarImg()

    self:UpdateStarUI()
end

function HalidomIconNew:OnInitTrans()
    local iconInst = self._iconInst

    self._uiStarTrans = CS.FindTrans(iconInst, "StarList")
    self._uiMaxStarImg = CS.FindTrans(iconInst, "MaxStarImg")
    self._uiIconBgTrans = CS.FindTrans(self._iconInst, "IconBg")

    CS.ShowObject(self._uiIconBgTrans, true)
    self._uiStarTrans.anchoredPosition = Vector2.New(0, -46)
    self._uiMaxStarImg.anchoredPosition = Vector2.New(0, -40)
    self:InitStartList()
end

-----------------------------------------------------------------

---@param halidomObj StructHalidomObjInfo
function HalidomIconNew:SetHalidomObj(halidomObj)
    self._dataType = HalidomIconNew.DATA_TYPE_SET
    self._halidomObj = halidomObj
    if halidomObj then
        self._refId = halidomObj.refId
    end
    self:InitInfo()
end

function HalidomIconNew:SetHalidomRefId(refId)
    self._dataType = HalidomIconNew.DATA_TYPE_NORMAL
    self._refId = refId
    self:InitInfo()
end

function HalidomIconNew:InitInfo()
    if not self._refId then
        return
    end

    local ref = self:GetHalidomRef(self._refId)
    if not ref then
        return
    end

    self._displayShowIcon = ref.icon

    local star = 0
    if self._dataType == HalidomIconNew.DATA_TYPE_SET then
        local halidomObj = self._halidomObj
        if halidomObj then
            self._showMaxStarImg = false
            if gModelHalidom then
                local imgInfo = gModelHalidom:GetShowStarImg(halidomObj.starLv, halidomObj.refId)
                self._showMaxStarImg = imgInfo.maxStarLv
                if not imgInfo.maxStarLv then
                    star = halidomObj.starLv
                end
            else
                star = halidomObj.starLv
            end
        end
    end
    self._displayStar = star
end

function HalidomIconNew:SetShowMaxStarImg(bShow)
    if self._showMaxStarImg == bShow then
        return
    end
    self._showMaxStarImg = bShow
    self:UpdateShowMaxStarImg()
end

function HalidomIconNew:UpdateShowMaxStarImg()
    if not self._uiMaxStarImg then
        return
    end

    local bShow = self._showMaxStarImg
    if self._uiMaxStarImg.gameObject.activeSelf ~= bShow then
        CS.ShowObject(self._uiMaxStarImg, bShow)
    end
end

function HalidomIconNew:GetNameData()
    return self._displayName, self._displayColor
end

function HalidomIconNew:ChangeToTipsState()
    CS.ShowObject(self._uiIconBgTrans, false)
    self._uiStarTrans.anchoredPosition = Vector2.New(0, -66)
    self._uiMaxStarImg.anchoredPosition = Vector2.New(0, -66)
end

-----------------------------------------------------------------

function HalidomIconNew:GetHalidomRef(refId)
    return GameTable.HalidomRef[refId]
end

function HalidomIconNew:GetHalidomStarRef(refId)
    return GameTable.HalidomStarRef[refId]
end

-----------------------------------------------------------------
return HalidomIconNew